ALTER TABLE supervision_task_schedule ADD COLUMN schedule_mode VARCHAR(32) NOT NULL DEFAULT 'CRON',ADD COLUMN rule_version INT NOT NULL DEFAULT 1,ADD COLUMN rule_json JSON NULL,ADD COLUMN start_at DATETIME NULL,ADD COLUMN end_at DATETIME NULL,ADD COLUMN misfire_policy VARCHAR(32) NOT NULL DEFAULT 'FIRE_ONCE_NOW',ADD COLUMN overlap_policy VARCHAR(32) NOT NULL DEFAULT 'SKIP',ADD COLUMN retry_policy_json JSON NULL,ADD COLUMN holiday_policy VARCHAR(32) NOT NULL DEFAULT 'NONE',ADD COLUMN next_fire_time DATETIME NULL;
CREATE TABLE IF NOT EXISTS supervision_task_trigger (id BIGINT PRIMARY KEY AUTO_INCREMENT,task_id BIGINT NOT NULL,trigger_key VARCHAR(128) NOT NULL,cron_expression VARCHAR(128) NULL,start_at DATETIME NULL,end_at DATETIME NULL,status TINYINT NOT NULL DEFAULT 1,UNIQUE KEY uk_task_trigger(task_id,trigger_key));
UPDATE supervision_task_schedule SET schedule_mode='CRON',rule_json=JSON_OBJECT('mode','CRON','cronExpression',cron_expression) WHERE rule_json IS NULL;